#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

function runCommand(command, description) {
  console.log(`\n>>> ${description}`);
  console.log(`Running: ${command}`);
  try {
    execSync(command, { stdio: 'inherit', encoding: 'utf-8' });
    console.log(`✓ ${description} completed successfully`);
  } catch (error) {
    console.error(`✗ ${description} failed with exit code ${error.status}`);
    process.exit(1);
  }
}

function verifyLockfile() {
  const lockfilePath = path.resolve(process.cwd(), 'package-lock.json');
  if (!fs.existsSync(lockfilePath)) {
    console.error('✗ package-lock.json not found. A lockfile is required to ensure reproducible builds and prevent supply chain attacks.');
    process.exit(1);
  }
  console.log('✓ package-lock.json found');
}

function auditDependencies() {
  console.log('\n>>> Running security audit');
  try {
    execSync('npm audit --audit-level=high', { stdio: 'inherit', encoding: 'utf-8' });
    console.log('✓ No high or critical vulnerabilities found');
  } catch (error) {
    console.warn('⚠ Security vulnerabilities detected. Review npm audit output above.');
    // Don't exit — allow pipeline to decide via separate audit step if needed
    // but log the warning prominently
    console.warn('⚠ Continuing with install, but vulnerabilities should be addressed.');
  }
}

function main() {
  console.log('=== CI/CD Dependency Installation Script ===');
  console.log(`Working directory: ${process.cwd()}`);
  console.log(`Node version: ${process.version}`);

  // 1. Verify lockfile exists to prevent supply chain attacks via dependency confusion
  verifyLockfile();

  // 2. Use npm ci instead of npm install:
  //    - npm ci uses the lockfile exactly (no modifications), preventing
  //      unexpected dependency resolution that could introduce malicious packages
  //    - npm ci fails if package-lock.json is out of sync with package.json
  //    - This prevents supply chain attacks where a compromised registry
  //      serves a different version than what was reviewed
  //    - Includes dev dependencies by default (no --production flag)
  //    - --ignore-scripts prevents arbitrary code execution from postinstall
  //      scripts in third-party packages, which is a common supply chain attack vector
  runCommand(
    'npm ci --ignore-scripts',
    'Installing dependencies from lockfile (npm ci, scripts disabled for security)'
  );

  // 3. Run security audit after install
  auditDependencies();

  // 4. Only run postinstall for known/trusted packages explicitly
  //    Instead of running ALL postinstall scripts (which could execute malicious code),
  //    we selectively rebuild only the packages that need native compilation
  //    or known setup steps.
  console.log('\n>>> Running trusted package rebuilds');

  // Read package.json to check if there's an explicit postinstall defined by the PROJECT (not dependencies)
  const packageJsonPath = path.resolve(process.cwd(), 'package.json');
  const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, 'utf-8'));

  // Rebuild native modules that are known to need compilation
  // This is safer than running all postinstall scripts from every dependency
  try {
    execSync('npm rebuild', { stdio: 'inherit', encoding: 'utf-8' });
    console.log('✓ Native modules rebuilt');
  } catch (error) {
    console.warn('⚠ npm rebuild encountered issues, continuing...');
  }

  // Only run the project's own postinstall script if it exists in package.json
  // This is the project's own trusted code, not arbitrary third-party scripts
  if (packageJson.scripts && packageJson.scripts.postinstall) {
    runCommand(
      'npm run postinstall',
      'Running project postinstall script (trusted, project-defined)'
    );
  } else {
    console.log('\n>>> No project-level postinstall script defined, skipping');
  }

  console.log('\n=== Dependency installation complete ===');
  console.log('Security measures applied:');
  console.log('  ✓ Used npm ci for deterministic installs from lockfile');
  console.log('  ✓ Disabled third-party postinstall scripts (--ignore-scripts)');
  console.log('  ✓ Ran security audit');
  console.log('  ✓ Only executed project-owned postinstall script');
}

main();